#include<cstdio>
#include<algorithm>
#include<cstdlib>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
//inline void print(const LL &p){printf("%lld",p);}
inline void print(const LL &p){if(p>9)print(p/10);putchar(p%10+'0');}
const int N=2e5+10;int x1[N],y1[N],x2[N],y2[N],Px[N],Py[N],px,py,posx,posy,qy1,qy2;LL w;
inline int fndx(const int &k){int l=1,r=px,t(1),m;while(l<=r)Px[m=(l+r)>>1]<=k?l=m+1,t=m:r=m-1;return t;}
inline int fndy(const int &k){int l=1,r=py,t(1),m;while(l<=r)Py[m=(l+r)>>1]<=k?l=m+1,t=m:r=m-1;return t;}

namespace SegY
{
	int Rt[N],cnt,T1,T2,T3;struct Seg{int l,r,vl,idx;LL sm;short key;}t[N*20];
	inline int Node(const int &Idx){t[++cnt].key=rand();t[cnt].idx=Idx;return cnt;}
//	inline void debug(){rep(1,cnt,i)printf("%d :: %d %d : %d %d %lld\n",i,t[i].l,t[i].r,t[i].vl,t[i].idx,t[i].sm);}
	inline void update(const int &x){t[x].sm=t[t[x].l].sm+t[t[x].r].sm+t[x].vl;}
	inline void split(int cur,int k,int &x,int &y)
	{
		if(!cur){x=y=0;return;}
		if(t[cur].idx<=k) {x=cur;split(t[cur].r,k,t[cur].r,y);}
		else{y=cur;split(t[cur].l,k,x,t[cur].l);}update(cur);
	}
	inline int merge(int x,int y)
	{
		if(!x||!y)return x|y;
		if(t[x].key<t[y].key){t[x].r=merge(t[x].r,y);update(x);return x;}
		t[y].l=merge(x,t[y].l);update(y);return y;
	}
	inline void add(const int &p)
	{
//		printf("add %d %d\n",p,posy);
		split(Rt[p],posy-1,T1,T2);split(T2,posy,T2,T3);
		if(!T2)T2=Node(posy);t[T2].vl+=w;t[T2].sm+=w;
		Rt[p]=merge(merge(T1,T2),T3);
	}
	inline LL qry(const int &p)
	{
		
		split(Rt[p],qy1-1,T1,T2);split(T2,qy2,T2,T3);LL res=t[T2].sm;
//		printf("qry %d [%d,%d] :: %d %d %d\n",p,qy1,qy2,T1,T2,T3); debug();
		Rt[p]=merge(merge(T1,T2),T3);return res;
	}
}
namespace SegX
{
	inline void add(){while(posx<=px)SegY::add(posx),posx+=(posx&-posx);}
	inline LL qry(int x){LL res=0;while(x)res+=SegY::qry(x),x^=(x&-x);return res;}
}
signed main()
{
//	FIN("data.in");FOUT("mine.out");
	
	srand(19260817);
	read();read();int Q=0;bool flag=true;while(flag)switch(read())
	{
		case 1: x1[++Q]=read();y1[Q]=read();x2[Q]=read();break;
		case 2: x1[++Q]=read();y1[Q]=read();x2[Q]=read();y2[Q]=read();break; case 3: flag=false;
	}
//	puts("QAQ");
	rep(1,Q,i)y2[i]?Px[++px]=x1[i],Px[++px]=x2[i],Py[++py]=y1[i],Py[++py]=y2[i]:(Px[++px]=x1[i],Py[++py]=y1[i]);
	std::sort(Px+1,Px+px+1);std::sort(Py+1,Py+py+1);px=std::unique(Px+1,Px+px+1)-Px-1;py=std::unique(Py+1,Py+py+1)-Py-1;
	rep(1,Q,i)if(y2[i])
	{
		qy1=fndy(y1[i]);qy2=fndy(y2[i]);
		print(SegX::qry(fndx(x2[i]))-SegX::qry(fndx(x1[i])-1));putchar('\n');
	}
	else {posx=fndx(x1[i]);posy=fndy(y1[i]);w=x2[i];SegX::add();}
//	printf("%d\n",SegY::cnt);
	 return 0;
}
